  1→import { NextRequest, NextResponse } from "next/server";
  2→import { v4 as uuidv4 } from "uuid";
  3→import { parseCSVDetailed, ColumnMapping } from "@/lib/csv-parser";
  4→import { analyzeSentiment } from "@/lib/comprehend";
  5→import { computeAnalytics } from "@/lib/analytics";
  6→import { setSession } from "@/lib/store";
  7→import { scrapeReviews } from "@/lib/scraper";
  8→import { Review, ReviewMetadata, ReviewSession } from "@/types";
  9→
 10→export async function POST(request: NextRequest) {
 11→  try {
 12→    const body = await request.json();
 13→    const { type, url, csvData, platform = "Amazon" } = body;
 14→
 15→    let reviews: Review[] = [];
 16→    let productName = "Unknown Product";
 17→    let productUrl = url || "";
 18→    let overallRating: number | undefined;
 19→    let totalGlobalRatings: number | undefined;
 20→    let csvWarnings: string[] = [];
 21→    let csvMapping: ColumnMapping | undefined;
 22→
 23→    if (type === "url" && url) {
 24→      try {
 25→        const result = await scrapeReviews(platform, url);
 26→        reviews = result.reviews;
 27→        productName = result.productName;
 28→        overallRating = result.overallRating;
 29→        totalGlobalRatings = result.totalGlobalRatings;
 30→      } catch (scrapeError) {
 31→        console.warn("Scrape failed:", scrapeError);
 32→        const message = scrapeError instanceof Error ? scrapeError.message : "Automated scraping failed.";
 33→        return NextResponse.json(
 34→          {
 35→            success: false,
 36→            error: message + " You can also try CSV upload instead.",
 37→          },
 38→          { status: 400 }
 39→        );
 40→      }
 41→    } else if (type === "csv" && csvData) {
 42→      const csvResult = parseCSVDetailed(csvData);
 43→      reviews = csvResult.reviews;
 44→      csvWarnings = csvResult.warnings;
 45→      csvMapping = csvResult.mapping;
 46→      productName = body.productName || "Uploaded Product";
 47→
 48→      if (reviews.length === 0) {
 49→        return NextResponse.json(
 50→          {
 51→            success: false,
 52→            error: csvWarnings.length > 0
 53→              ? csvWarnings.join(" ")
 54→              : "No reviews could be extracted. Please check your CSV format.",
 55→            columnMapping: csvMapping,
 56→          },
 57→          { status: 400 }
 58→        );
 59→      }
 60→    } else {
 61→      return NextResponse.json(
 62→        { success: false, error: "Invalid request. Provide URL or CSV data." },
 63→        { status: 400 }
 64→      );
 65→    }
 66→
 67→    if (reviews.length === 0) {
 68→      return NextResponse.json(
 69→        {
 70→          success: false,
 71→          error: "No reviews found. Please check your input and try again.",
 72→        },
 73→        { status: 400 }
 74→      );
 75→    }
 76→
 77→    // Analyze sentiment with Amazon Comprehend
 78→    const enrichedReviews = await analyzeSentiment(reviews);
 79→
 80→    // Compute analytics
 81→    const analytics = computeAnalytics(enrichedReviews);
 82→
 83→    // Sort reviews by date (newest first)
 84→    const dates = enrichedReviews
 85→      .map((r) => r.date)
 86→      .filter(Boolean)
 87→      .sort();
 88→
 89→    const metadata: ReviewMetadata = {
 90→      platform,
 91→      productName,
 92→      productUrl,
 93→      totalReviews: enrichedReviews.length,
 94→      averageRating: analytics.averageRating,
 95→      overallRating,
 96→      totalGlobalRatings,
 97→      dateRange: {
 98→        earliest: dates[0] || "Unknown",
 99→        latest: dates[dates.length - 1] || "Unknown",
100→      },
101→      scrapedAt: new Date().toISOString(),
102→    };
103→
104→    // Store session
105→    const sessionId = uuidv4();
106→    const session: ReviewSession = {
107→      sessionId,
108→      reviews: enrichedReviews,
109→      metadata,
110→      analytics,
111→    };
112→    setSession(sessionId, session);
113→
114→    return NextResponse.json({
115→      success: true,
116→      sessionId,
117→      metadata,
118→      reviews: enrichedReviews,
119→      analytics,
120→      reviewCount: enrichedReviews.length,
121→      ...(csvMapping && { columnMapping: csvMapping, csvWarnings }),
122→    });
123→  } catch (error) {
124→    console.error("Ingest error:", error);
125→    return NextResponse.json(
126→      {
127→        success: false,
128→        error: "Failed to process reviews. Please try again.",
129→      },
130→      { status: 500 }
131→    );
132→  }
133→}
