17→
18→  const navItems = [
19→    { href: "/", label: "Ingest", icon: Search, alwaysEnabled: true },
20→    { href: "/dashboard", label: "Dashboard", icon: BarChart3, alwaysEnabled: false },
21→  ];
22→
23→  return (
24→    <header className="sticky top-0 z-50 glass-strong">
25→      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
26→        <div className="flex items-center justify-between h-16">
27→          <Link href="/" className="flex items-center gap-2.5">
28→            <Image
29→              src="/logo.svg"
30→              alt="ReviewLens AI"
31→              width={36}
32→              height={36}
33→              className="rounded-xl shadow-lg shadow-violet-500/25"
34→              priority
35→            />
36→            <span className="text-xl font-bold tracking-tight">
37→              Review<span className="gradient-text">Lens</span>
38→              <span className="text-violet-400/70 ml-0.5 text-sm font-medium">AI</span>
39→            </span>
40→          </Link>
41→
42→          <nav className="flex items-center gap-1">
43→            {navItems.map((item) => {
