53→                  >
54→                    <Icon className="w-4 h-4" />
55→                    <span className="hidden sm:inline">{item.label}</span>
56→                  </span>
57→                );
58→              }
59→
60→              return (
61→                <Link
62→                  key={item.href}
63→                  href={item.href}
64→                  className={cn(
65→                    "flex items-center gap-2 px-3.5 py-2 rounded-lg text-sm font-medium transition-all duration-200 cursor-pointer",
66→                    isActive
67→                      ? "bg-gradient-to-r from-violet-500/20 to-indigo-500/20 text-violet-300 border border-violet-500/20 shadow-lg shadow-violet-500/10"
