  3→import { useState, useRef, useEffect, useCallback } from "react";
  4→import { Textarea } from "@/components/ui/textarea";
  5→import {
  6→  Send,
  7→  Loader2,
  8→  Shield,
  9→  ShieldAlert,
 10→  Bot,
 11→  User,
 12→  Sparkles,
 13→} from "lucide-react";
 14→import ReactMarkdown from "react-markdown";
 15→import { ChatMessage, ReviewMetadata } from "@/types";
 16→import { cn } from "@/lib/utils";
 17→
 18→interface ChatInterfaceProps {
 19→  sessionId: string;
 20→  metadata: ReviewMetadata;
 21→  compact?: boolean;
 22→}
 23→
 24→const SUGGESTED_QUESTIONS = [
 25→  "What are the most common complaints?",
 26→  "Summarize the positive reviews",
 27→  "What do customers say about quality?",
 28→  "Are there any recurring issues?",
 29→  "What features do reviewers mention most?",
 30→  "Compare 5-star vs 1-star review themes",
 31→];
 32→
 33→export default function ChatInterface({ sessionId, metadata, compact }: ChatInterfaceProps) {
 34→  const [messages, setMessages] = useState<ChatMessage[]>([]);
 35→  const [input, setInput] = useState("");
 36→  const [isStreaming, setIsStreaming] = useState(false);
 37→  const scrollContainerRef = useRef<HTMLDivElement>(null);
 38→  const messagesEndRef = useRef<HTMLDivElement>(null);
 39→  const textareaRef = useRef<HTMLTextAreaElement>(null);
 40→  const scrollToBottom = useCallback(() => {
 41→    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
 42→  }, []);
 43→
 44→  // Auto-scroll on every message update (including streaming chunks)
 45→  useEffect(() => {
 46→    scrollToBottom();
 47→  }, [messages, scrollToBottom]);
 48→
 49→  const sendMessage = async (messageText?: string) => {
 50→    const text = messageText || input.trim();
 51→    if (!text || isStreaming) return;
 52→
 53→    const userMessage: ChatMessage = {
 54→      id: crypto.randomUUID(),
 55→      role: "user",
 56→      content: text,
 57→      timestamp: new Date().toISOString(),
 58→    };
 59→
 60→    setMessages((prev) => [...prev, userMessage]);
 61→    setInput("");
 62→    setIsStreaming(true);
 63→
 64→    const assistantId = crypto.randomUUID();
 65→    const assistantMessage: ChatMessage = {
 66→      id: assistantId,
 67→      role: "assistant",
 68→      content: "",
 69→      timestamp: new Date().toISOString(),
 70→    };
 71→    setMessages((prev) => [...prev, assistantMessage]);
 72→
 73→    try {
 74→      const history = messages.map((m) => ({
 75→        role: m.role,
 76→        content: m.content,
 77→      }));
 78→
 79→      // On first message, send session data so the server can hydrate its store
 80→      // (Turbopack runs route handlers in separate workers with isolated memory)
 81→      let sessionData: Record<string, unknown> | undefined;
 82→      if (messages.length === 0) {
 83→        try {
 84→          const reviews = JSON.parse(sessionStorage.getItem("reviewlens_reviews") || "[]");
 85→          const meta = JSON.parse(sessionStorage.getItem("reviewlens_metadata") || "{}");
 86→          const analytics = JSON.parse(sessionStorage.getItem("reviewlens_analytics") || "{}");
 87→          sessionData = { reviews, metadata: meta, analytics };
 88→        } catch { /* proceed without */ }
 89→      }
 90→
 91→      const response = await fetch("/api/chat", {
 92→        method: "POST",
 93→        headers: {
 94→          "Content-Type": "application/json",
 95→          "Accept-Encoding": "identity",
 96→          "Accept": "text/event-stream",
 97→        },
 98→        body: JSON.stringify({ sessionId, message: text, history, sessionData }),
 99→      });
100→
101→      if (!response.ok) throw new Error("Chat request failed");
102→
103→      const reader = response.body?.getReader();
104→      if (!reader) throw new Error("No response stream");
105→
106→      const decoder = new TextDecoder();
107→      let buffer = "";
108→
109→      for (;;) {
110→        const { done, value } = await reader.read();
111→        if (done) break;
112→
113→        buffer += decoder.decode(value, { stream: true });
114→
115→        let boundary = buffer.indexOf("\n\n");
116→        while (boundary !== -1) {
117→          const line = buffer.slice(0, boundary);
118→          buffer = buffer.slice(boundary + 2);
119→
120→          if (line.startsWith("data: ")) {
121→            try {
122→              const data = JSON.parse(line.slice(6));
123→              if (data.type === "text") {
124→                setMessages((prev) =>
125→                  prev.map((m) =>
126→                    m.id === assistantId ? { ...m, content: m.content + data.content } : m
127→                  )
128→                );
129→              } else if (data.type === "guard") {
130→                setMessages((prev) =>
131→                  prev.map((m) =>
132→                    m.id === assistantId
133→                      ? { ...m, content: data.content, scopeGuardTriggered: true, guardrailAction: data.action }
134→                      : m
135→                  )
136→                );
137→              } else if (data.type === "error") {
138→                setMessages((prev) =>
139→                  prev.map((m) =>
140→                    m.id === assistantId ? { ...m, content: data.content } : m
141→                  )
142→                );
143→              }
144→            } catch {
145→              /* skip invalid JSON */
146→            }
147→          }
148→
149→          boundary = buffer.indexOf("\n\n");
150→        }
151→      }
152→    } catch {
153→      setMessages((prev) =>
154→        prev.map((m) =>
155→          m.id === assistantId
156→            ? { ...m, content: "Sorry, something went wrong. Please try again." }
157→            : m
158→        )
159→      );
160→    } finally {
161→      setIsStreaming(false);
162→    }
