  1→import { parse } from "csv-parse/sync";
  2→import { Review } from "@/types";
  3→import { v4 as uuidv4 } from "uuid";
  4→
  5→/* ------------------------------------------------------------------ */
  6→/*  Keyword pools — used for fuzzy header matching                     */
  7→/* ------------------------------------------------------------------ */
  8→const FIELD_KEYWORDS: Record<keyof Omit<Review, "id" | "sentiment">, string[]> = {
  9→  rating: ["rating", "ratings", "star", "stars", "score", "grade", "rank", "note", "point", "points", "evaluation"],
 10→  title: ["title", "headline", "heading", "subject", "summary"],
 11→  body: [
 12→    "body", "text", "review", "reviews", "content", "comment", "comments",
 13→    "description", "feedback", "opinion", "message", "detail", "details",
 14→    "review_text", "review_body", "review_content", "reviewtext",
 15→  ],
 16→  date: ["date", "time", "timestamp", "datetime", "created", "posted", "published", "reviewed", "created_at", "updated_at"],
 17→  reviewer: ["reviewer", "author", "user", "name", "username", "user_name", "customer", "writer", "profile", "display_name"],
 18→  verified: ["verified", "verified_purchase", "is_verified", "confirmed", "trusted"],
 19→};
 20→
 21→/* ------------------------------------------------------------------ */
 22→/*  Fuzzy helpers                                                      */
 23→/* ------------------------------------------------------------------ */
 24→
 25→/** Normalize a header string for comparison */
 26→function normalize(s: string): string {
 27→  return s
 28→    .toLowerCase()
 29→    .replace(/[^a-z0-9]+/g, " ")
 30→    .trim();
 31→}
 32→
 33→/** Simple word-overlap similarity between 0 and 1 */
 34→function headerSimilarity(header: string, keywords: string[]): number {
 35→  const norm = normalize(header);
 36→  // Exact match against any keyword
 37→  for (const kw of keywords) {
 38→    if (norm === kw) return 1;
 39→  }
 40→  // Check if header contains a keyword or vice-versa
 41→  for (const kw of keywords) {
 42→    if (norm.includes(kw) || kw.includes(norm)) return 0.8;
 43→  }
 44→  // Word overlap
 45→  const headerWords = norm.split(/\s+/);
 46→  let best = 0;
 47→  for (const kw of keywords) {
 48→    const kwWords = kw.split(/\s+/);
 49→    const overlap = headerWords.filter((w) => kwWords.includes(w)).length;
 50→    const score = overlap / Math.max(headerWords.length, kwWords.length);
 51→    if (score > best) best = score;
 52→  }
 53→  return best * 0.6;
 54→}
 55→
 56→/* ------------------------------------------------------------------ */
 57→/*  Content-based heuristics                                           */
 58→/* ------------------------------------------------------------------ */
 59→
 60→const DATE_PATTERNS = [
 61→  /^\d{4}[-/]\d{1,2}[-/]\d{1,2}/,           // 2024-01-15
 62→  /^\d{1,2}[-/]\d{1,2}[-/]\d{2,4}/,         // 15/01/2024 or 1-15-24
 63→  /^[A-Za-z]{3,9}\s+\d{1,2},?\s+\d{4}/,     // January 15, 2024
 64→  /^\d{1,2}\s+[A-Za-z]{3,9}\s+\d{4}/,       // 15 January 2024
 65→  /^[A-Za-z]{3,9}\s+\d{4}/,                  // March 2024
 66→  /^\d{4}[-/]\d{1,2}[-/]\d{1,2}T/,           // ISO 8601
 67→];
 68→
 69→function looksLikeDate(value: string): boolean {
 70→  const trimmed = value.trim();
 71→  return DATE_PATTERNS.some((p) => p.test(trimmed));
 72→}
 73→
 74→function looksLikeNumber(value: string): boolean {
 75→  return /^-?\d+(\.\d+)?$/.test(value.trim());
 76→}
 77→
 78→function looksLikeBoolean(value: string): boolean {
 79→  return ["true", "false", "yes", "no", "1", "0", "y", "n"].includes(value.trim().toLowerCase());
 80→}
 81→
 82→interface ColumnProfile {
 83→  header: string;
 84→  avgLength: number;
 85→  maxLength: number;
 86→  numericRatio: number;    // fraction of non-empty values that are numeric
 87→  numericValues: number[]; // parsed numeric values
 88→  dateRatio: number;       // fraction that look like dates
 89→  boolRatio: number;       // fraction that look like booleans
 90→  emptyRatio: number;
 91→  sampleValues: string[];
 92→}
 93→
 94→function profileColumns(headers: string[], rows: Record<string, string>[]): Map<string, ColumnProfile> {
 95→  const profiles = new Map<string, ColumnProfile>();
 96→  const sampleSize = Math.min(rows.length, 50);
 97→  const sample = rows.slice(0, sampleSize);
 98→
 99→  for (const header of headers) {
100→    const values = sample.map((r) => (r[header] ?? "").trim());
101→    const nonEmpty = values.filter((v) => v.length > 0);
102→
103→    const numericValues: number[] = [];
104→    let dateCount = 0;
105→    let boolCount = 0;
106→
107→    for (const v of nonEmpty) {
108→      if (looksLikeNumber(v)) numericValues.push(parseFloat(v));
109→      if (looksLikeDate(v)) dateCount++;
110→      if (looksLikeBoolean(v)) boolCount++;
111→    }
112→
113→    profiles.set(header, {
114→      header,
115→      avgLength: nonEmpty.length > 0 ? nonEmpty.reduce((s, v) => s + v.length, 0) / nonEmpty.length : 0,
116→      maxLength: nonEmpty.length > 0 ? Math.max(...nonEmpty.map((v) => v.length)) : 0,
117→      numericRatio: nonEmpty.length > 0 ? numericValues.length / nonEmpty.length : 0,
118→      numericValues,
119→      dateRatio: nonEmpty.length > 0 ? dateCount / nonEmpty.length : 0,
120→      boolRatio: nonEmpty.length > 0 ? boolCount / nonEmpty.length : 0,
121→      emptyRatio: values.length > 0 ? (values.length - nonEmpty.length) / values.length : 1,
122→      sampleValues: nonEmpty.slice(0, 5),
123→    });
124→  }
125→
126→  return profiles;
127→}
128→
129→/* ------------------------------------------------------------------ */
130→/*  Column scoring — combine header + content signals                  */
131→/* ------------------------------------------------------------------ */
132→
133→type ReviewField = keyof Omit<Review, "id" | "sentiment">;
134→
135→interface FieldScore {
136→  header: string;
137→  score: number;
138→}
139→
140→function scoreColumns(
141→  profiles: Map<string, ColumnProfile>,
142→): Record<ReviewField, FieldScore | null> {
143→  const candidates: Record<ReviewField, FieldScore[]> = {
144→    rating: [],
145→    title: [],
146→    body: [],
147→    date: [],
148→    reviewer: [],
149→    verified: [],
150→  };
151→
152→  for (const [header, prof] of profiles) {
153→    // --- Rating ---
154→    const ratingHeaderScore = headerSimilarity(header, FIELD_KEYWORDS.rating);
155→    let ratingContentScore = 0;
156→    if (prof.numericRatio > 0.7 && prof.numericValues.length > 0) {
157→      const min = Math.min(...prof.numericValues);
158→      const max = Math.max(...prof.numericValues);
159→      // Likely a rating if values are in a small bounded range
160→      if (min >= 0 && max <= 10 && prof.avgLength < 5) {
161→        ratingContentScore = 0.7;
162→        if (max <= 5) ratingContentScore = 0.9;
163→      }
164→    }
165→    candidates.rating.push({ header, score: Math.max(ratingHeaderScore, ratingContentScore) });
166→
167→    // --- Body (review text) ---
168→    const bodyHeaderScore = headerSimilarity(header, FIELD_KEYWORDS.body);
169→    let bodyContentScore = 0;
170→    if (prof.avgLength > 40 && prof.numericRatio < 0.3 && prof.dateRatio < 0.3) {
171→      bodyContentScore = Math.min(1, prof.avgLength / 200); // longer text = more likely body
172→    }
173→    candidates.body.push({ header, score: Math.max(bodyHeaderScore, bodyContentScore) });
174→
175→    // --- Title ---
176→    const titleHeaderScore = headerSimilarity(header, FIELD_KEYWORDS.title);
177→    let titleContentScore = 0;
178→    if (prof.avgLength > 5 && prof.avgLength < 100 && prof.numericRatio < 0.3 && prof.dateRatio < 0.3) {
179→      titleContentScore = 0.3; // moderate signal
180→    }
181→    candidates.title.push({ header, score: Math.max(titleHeaderScore, titleContentScore) });
182→
183→    // --- Date ---
184→    const dateHeaderScore = headerSimilarity(header, FIELD_KEYWORDS.date);
185→    const dateContentScore = prof.dateRatio > 0.5 ? prof.dateRatio : 0;
186→    candidates.date.push({ header, score: Math.max(dateHeaderScore, dateContentScore) });
187→
188→    // --- Reviewer ---
189→    const reviewerHeaderScore = headerSimilarity(header, FIELD_KEYWORDS.reviewer);
190→    let reviewerContentScore = 0;
191→    if (prof.avgLength > 2 && prof.avgLength < 40 && prof.numericRatio < 0.2 && prof.dateRatio < 0.2 && prof.boolRatio < 0.2) {
192→      reviewerContentScore = 0.2;
193→    }
194→    candidates.reviewer.push({ header, score: Math.max(reviewerHeaderScore, reviewerContentScore) });
195→
196→    // --- Verified ---
197→    const verifiedHeaderScore = headerSimilarity(header, FIELD_KEYWORDS.verified);
198→    const verifiedContentScore = prof.boolRatio > 0.7 ? prof.boolRatio * 0.6 : 0;
199→    candidates.verified.push({ header, score: Math.max(verifiedHeaderScore, verifiedContentScore) });
200→  }
201→
202→  // Assign fields greedily — highest-scoring first, no column reuse
203→  const assigned = new Set<string>();
204→  const result: Record<ReviewField, FieldScore | null> = {
205→    rating: null,
206→    title: null,
207→    body: null,
208→    date: null,
209→    reviewer: null,
210→    verified: null,
211→  };
212→
213→  // Priority order: body first (most important), then rating, title, date, reviewer, verified
214→  // Title before reviewer so a "title" header isn't stolen by reviewer's content heuristic
215→  const fieldPriority: ReviewField[] = ["body", "rating", "title", "date", "reviewer", "verified"];
216→
217→  for (const field of fieldPriority) {
218→    const sorted = candidates[field]
219→      .filter((c) => !assigned.has(c.header) && c.score > 0.15)
220→      .sort((a, b) => b.score - a.score);
221→
222→    if (sorted.length > 0) {
223→      result[field] = sorted[0];
224→      assigned.add(sorted[0].header);
225→    }
226→  }
227→
228→  return result;
229→}
230→
231→/* ------------------------------------------------------------------ */
232→/*  Rating normalization                                               */
233→/* ------------------------------------------------------------------ */
234→
235→function detectRatingScale(values: number[]): number {
236→  if (values.length === 0) return 5;
237→  const max = Math.max(...values);
238→  if (max <= 5) return 5;
239→  if (max <= 10) return 10;
240→  if (max <= 100) return 100;
241→  return max;
242→}
243→
244→function normalizeRating(value: number, scale: number): number {
245→  if (scale === 5) return Math.min(5, Math.max(0, value));
246→  const normalized = (value / scale) * 5;
247→  return Math.min(5, Math.max(0, Math.round(normalized * 10) / 10));
248→}
249→
250→/* ------------------------------------------------------------------ */
251→/*  Date normalization                                                 */
252→/* ------------------------------------------------------------------ */
253→
254→function normalizeDate(raw: string): string {
255→  const trimmed = raw.trim();
256→  if (!trimmed) return "";
257→
258→  // Try native Date parsing — handles most standard formats
259→  const parsed = new Date(trimmed);
260→  if (!isNaN(parsed.getTime()) && parsed.getFullYear() > 1970 && parsed.getFullYear() < 2100) {
261→    return parsed.toISOString().split("T")[0]; // YYYY-MM-DD
262→  }
263→
264→  // Try DD/MM/YYYY or DD-MM-YYYY (ambiguous — assume day-first if first part > 12)
265→  const dmy = trimmed.match(/^(\d{1,2})[/-](\d{1,2})[/-](\d{2,4})$/);
266→  if (dmy) {
267→    let [, d, m, y] = dmy;
268→    if (y.length === 2) y = (parseInt(y) > 50 ? "19" : "20") + y;
269→    // If first number > 12, it's definitely the day
270→    if (parseInt(d) > 12) {
271→      const attempt = new Date(`${y}-${m.padStart(2, "0")}-${d.padStart(2, "0")}`);
272→      if (!isNaN(attempt.getTime())) return attempt.toISOString().split("T")[0];
273→    }
274→  }
275→
276→  return trimmed; // Return as-is if we can't parse
277→}
278→
279→/* ------------------------------------------------------------------ */
280→/*  Public API                                                         */
281→/* ------------------------------------------------------------------ */
282→
283→export interface ColumnMapping {
284→  rating: string | null;
285→  title: string | null;
286→  body: string | null;
287→  date: string | null;
288→  reviewer: string | null;
289→  verified: string | null;
290→}
291→
292→export interface ParseResult {
293→  reviews: Review[];
294→  mapping: ColumnMapping;
295→  warnings: string[];
296→  ratingScale: number;
297→}
298→
299→export function parseCSV(csvContent: string): Review[] {
300→  const result = parseCSVDetailed(csvContent);
301→  return result.reviews;
302→}
303→
304→export function parseCSVDetailed(csvContent: string): ParseResult {
305→  const warnings: string[] = [];
306→
307→  const records = parse(csvContent, {
308→    columns: true,
309→    skip_empty_lines: true,
310→    trim: true,
311→    relax_column_count: true,
312→    relax_quotes: true,
313→  }) as Record<string, string>[];
314→
315→  if (records.length === 0) {
316→    return { reviews: [], mapping: { rating: null, title: null, body: null, date: null, reviewer: null, verified: null }, warnings: ["CSV contains no data rows."], ratingScale: 5 };
317→  }
318→
319→  const headers = Object.keys(records[0]);
320→  const profiles = profileColumns(headers, records);
321→  const mapping = scoreColumns(profiles);
322→
323→  // Build the column mapping for transparency
324→  const columnMapping: ColumnMapping = {
325→    rating: mapping.rating?.header ?? null,
326→    title: mapping.title?.header ?? null,
327→    body: mapping.body?.header ?? null,
328→    date: mapping.date?.header ?? null,
329→    reviewer: mapping.reviewer?.header ?? null,
330→    verified: mapping.verified?.header ?? null,
331→  };
332→
333→  if (!columnMapping.body) {
334→    warnings.push("Could not detect a review text column. The longest text column will be used as fallback.");
335→    // Fallback: pick the column with the longest average text
336→    let bestHeader: string | null = null;
337→    let bestAvg = 0;
338→    for (const [header, prof] of profiles) {
339→      if (prof.avgLength > bestAvg) {
340→        bestAvg = prof.avgLength;
341→        bestHeader = header;
342→      }
343→    }
344→    if (bestHeader) columnMapping.body = bestHeader;
345→  }
346→
347→  if (!columnMapping.body) {
348→    warnings.push("No text column found — cannot extract reviews.");
349→    return { reviews: [], mapping: columnMapping, warnings, ratingScale: 5 };
350→  }
351→
352→  // Detect rating scale
353→  let ratingScale = 5;
354→  if (columnMapping.rating) {
355→    const prof = profiles.get(columnMapping.rating);
356→    if (prof) ratingScale = detectRatingScale(prof.numericValues);
357→  }
358→
359→  if (ratingScale !== 5) {
360→    warnings.push(`Detected ${ratingScale}-point rating scale — ratings will be normalized to 1–5.`);
361→  }
362→
363→  // Build reviews
364→  let skippedEmpty = 0;
365→  const reviews: Review[] = [];
366→
367→  for (const row of records) {
368→    const bodyText = (columnMapping.body ? row[columnMapping.body] ?? "" : "").trim();
369→    if (!bodyText) {
370→      skippedEmpty++;
371→      continue;
372→    }
373→
374→    const rawRating = columnMapping.rating ? parseFloat(row[columnMapping.rating] || "0") : 0;
375→    const rating = columnMapping.rating && !isNaN(rawRating) ? normalizeRating(rawRating, ratingScale) : 0;
376→    const title = columnMapping.title ? (row[columnMapping.title] ?? "").trim() : "";
377→    const rawDate = columnMapping.date ? (row[columnMapping.date] ?? "").trim() : "";
378→    const date = normalizeDate(rawDate);
379→    const reviewer = columnMapping.reviewer ? (row[columnMapping.reviewer] ?? "").trim() || "Anonymous" : "Anonymous";
380→    const verifiedRaw = columnMapping.verified ? (row[columnMapping.verified] ?? "").trim().toLowerCase() : "";
381→    const verified = ["true", "yes", "1", "y"].includes(verifiedRaw);
382→
383→    reviews.push({
384→      id: uuidv4(),
385→      rating,
386→      title,
387→      body: bodyText,
388→      date,
389→      reviewer,
390→      verified,
391→    });
392→  }
393→
394→  if (skippedEmpty > 0) {
395→    warnings.push(`Skipped ${skippedEmpty} row(s) with empty review text.`);
396→  }
397→
398→  return { reviews, mapping: columnMapping, warnings, ratingScale };
399→}
