  1→import { Review } from "@/types";
  2→import { v4 as uuidv4 } from "uuid";
  3→
  4→const APIFY_BASE_URL = "https://api.apify.com/v2";
  5→
  6→const ACTOR_IDS: Record<string, string> = {
  7→  Amazon: "junglee~amazon-reviews-scraper",
  8→  "Google Maps": "compass~google-maps-reviews-scraper",
  9→};
 10→
 11→export interface ScrapeResult {
 12→  reviews: Review[];
 13→  productName: string;
 14→  overallRating?: number;
 15→  totalGlobalRatings?: number;
 16→}
 17→
 18→// --- Shared Apify helpers ---
 19→
 20→interface ApifyRunResponse {
 21→  data: {
 22→    id: string;
 23→    status: string;
 24→    defaultDatasetId: string;
 25→  };
 26→}
 27→
 28→async function apifyFetch(path: string, options?: RequestInit): Promise<Response> {
 29→  const token = process.env.APIFY_API_TOKEN;
 30→  if (!token) {
 31→    throw new Error("APIFY_API_TOKEN not configured");
 32→  }
 33→  const url = `${APIFY_BASE_URL}${path}${path.includes("?") ? "&" : "?"}token=${token}`;
 34→  return fetch(url, options);
 35→}
 36→
 37→async function waitForRun(runId: string, actorId: string, timeoutMs = 120000): Promise<ApifyRunResponse["data"]> {
 38→  const start = Date.now();
 39→  while (Date.now() - start < timeoutMs) {
 40→    const res = await apifyFetch(`/acts/${actorId}/runs/${runId}`);
 41→    const data = (await res.json()) as ApifyRunResponse;
 42→    if (data.data.status === "SUCCEEDED") return data.data;
 43→    if (data.data.status === "FAILED" || data.data.status === "ABORTED") {
 44→      throw new Error(`Apify run ${data.data.status.toLowerCase()}`);
 45→    }
 46→    await new Promise((r) => setTimeout(r, 3000));
 47→  }
 48→  throw new Error("Apify run timed out");
 49→}
 50→
 51→async function startAndCollect(actorId: string, input: Record<string, unknown>): Promise<unknown[]> {
 52→  const startRes = await apifyFetch(`/acts/${actorId}/runs`, {
 53→    method: "POST",
 54→    headers: { "Content-Type": "application/json" },
 55→    body: JSON.stringify(input),
 56→  });
 57→
 58→  if (!startRes.ok) {
 59→    const err = await startRes.text();
 60→    throw new Error(`Failed to start Apify actor: ${err}`);
 61→  }
 62→
 63→  const startData = (await startRes.json()) as ApifyRunResponse;
 64→  const run = await waitForRun(startData.data.id, actorId);
 65→
 66→  const datasetRes = await apifyFetch(`/datasets/${run.defaultDatasetId}/items?format=json`);
 67→  if (!datasetRes.ok) {
 68→    throw new Error("Failed to fetch Apify dataset results");
 69→  }
 70→
 71→  const items = (await datasetRes.json()) as unknown[];
 72→  if (!items || items.length === 0) {
 73→    throw new Error("No reviews found. The page may have no reviews or the scraper couldn't access them.");
 74→  }
 75→
 76→  return items;
 77→}
